#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N,M,K,X; scanf("%lld %lld %lld %lld", &N, &M, &K, &X);
        long long blockDays = K * N + M;
        long long rem = X % blockDays;
        long long normalDays = (K - 1) * N;
        if(rem == 0 || rem > normalDays) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

