#!/usr/bin/env python3
import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); K = int(next(it)); X = int(next(it))
        block_days = K * N + M
        rem = X % block_days
        normal_days = (K - 1) * N
        if rem == 0 or rem > normal_days:
            out.append("YES")
        else:
            out.append("NO")
    sys.stdout.write("\n".join(out))
if __name__ == "__main__":
    solve()

